mapper.select:
SELECT e.id AS "id", e.register_id AS "registerId", e.department_id AS "departmentId", e.event_type AS "eventType", e.actor_type AS "actorType", e.actor_id AS "actorId", e.title AS "title", e.summary AS "summary", e.payload AS "payload", e.ref_table AS "refTable", e.ref_id AS "refId", e.occurred_at AS "occurredAt", r.real_name AS "patientName", r.case_number AS "caseNumber" FROM follow_up_history_event e INNER JOIN register r ON r.id = e.register_id
AND e.register_id = #{registerId}
AND e.department_id = #{departmentId}
AND e.occurred_at::date >= #{from}
AND e.occurred_at::date <= #{to}
AND e.event_type = #{eventType}
ORDER BY e.occurred_at DESC, e.id DESC
LIMIT #{limit}
